// Compile-time constants injected by vite.config.ts via the `define` option.
// `__APP_VERSION__` mirrors package.json's "version" field; `__APP_GITHASH__`
// is the short git SHA of the build's HEAD (or "nogit" when not in a checkout).
declare const __APP_VERSION__: string;
declare const __APP_GITHASH__: string;
